INSERT INTO tunes (id,ts,title,artist,genre,description,historical,uploader_id,mp3_key,spotify_id,duration_ms,popularity,added_at) VALUES (21,20071025010217,'If You Rescue Me','Gael Garcia Bernal & Co','','Upon watching Michel Gondry s latest movie The Science of Sleep, I fell in love with this song. The rest of the soundtrack is also amazing. This version of the song was brilliantly composed by Jean-Michel Bernard but it was originally made famous by The Velvet Underground. Their version is titled  Afterhours. 
